'use strict'

const chalk = require('chalk')
const { stop, runFastify } = require('../../start')

const {
  GRACEFUL_SHUT,
  READY,
  TIMEOUT
} = require('./constants.js')

let fastify

function exit () {
  if (this) { console.log(chalk.red(this.message)) }
  process.exit(1)
}

process.on('message', function (event) {
  if (event === GRACEFUL_SHUT) {
    const message = chalk.red('[fastify-cli] process forced end')
    setTimeout(exit.bind({ message }), TIMEOUT).unref()
    if (fastify) {
      fastify.close(() => {
        process.exit(0)
      })
    } else {
      process.exit(0)
    }
  }
})

process.on('uncaughtException', (err) => {
  console.log(chalk.red(err))
  const message = chalk.red('[fastify-cli] app crashed - waiting for file changes before starting...')
  exit.bind({ message })()
})

const main = async () => {
  fastify = await runFastify(process.argv.splice(2))
  const type = process.env.childEvent

  process.send({ type, err: null })

  try {
    await fastify.ready()
    process.send({ type: READY })
  } catch (err) {
    stop(err)
  }
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})

import { getAllProducts, getOneProduct, createProduct, updateProduct, deleteProduct } from '../dao/index';

async function routes(fastify) {

	fastify.get('/', async (req, res) => {
		req.log.info('list products from db');
		const products = await getAllProducts();
		res.status(200).send(products);
	});

	fastify.get('/:_id', async (req, res) => {
		req.log.info('Get one product from db');
		const products = await getOneProduct(req.params._id);
		res.status(200).send(products);
	});

	fastify.post('/', async (req, res) => {
		req.log.info('Add products to db');
		const products = await createProduct(req.body);
		res.status(201).send(products);
	});

	fastify.put('/:_id', async (req, res) => {
		req.log.info('Update product to db');
		const products = await updateProduct(req.params._id, req.body);
		res.status(200).send(products);
	});

	fastify.delete('/:_id', async (req, res) => {
		req.log.info(`delete product ${req.params._id} from db`);
		await deleteProduct(req.params._id);
		res.code(200).send('OK');
	});

}

module.exports = routes;

import { EventEmitter } from 'node:events';
import type { FastifyPluginAsyncTypebox } from '@fastify/type-provider-typebox';
import { Type } from 'typebox';

export default (async (app) => {
  // When integrating with BullMQ, Redis Pub/Sub can be used to trigger SSE
  const sseEmitter = new EventEmitter();

  app.get(
    '',
    {
      schema: {
        params: Type.Object({
          id: Type.String(),
        }),
      },
    },
    (request, reply) => {
      const { id } = request.params;

      function eventId(data?: string | object) {
        reply.sse({ id, data });
        reply.sse({ event: 'end' });
      }

      sseEmitter.on(`/sse/event/${id}`, eventId);

      request.raw.on('close', () => {
        sseEmitter.off(`/sse/event/${id}`, eventId);
      });
    },
  );

  app.post(
    '',
    {
      schema: {
        params: Type.Object({
          id: Type.String(),
        }),
      },
    },
    async (request, reply) => {
      const { id } = request.params;
      sseEmitter.emit(`/sse/event/${id}`, request.body);
      return reply.send({ message: 'Data sent to client' });
    },
  );
}) as FastifyPluginAsyncTypebox;

import type { ObjectId } from '@fastify/mongodb';
import type { FastifyPluginAsyncTypebox } from '@fastify/type-provider-typebox';
import { Type } from 'typebox';

const querystring = Type.Object({
  value: Type.String(),
  category: Type.Optional(Type.String()),
});

const response = {
  '2xx': Type.Array(
    Type.Object({
      label: Type.String(),
      value: Type.String(),
    }),
  ),
};

export default (async (app) => {
  app.get('', { schema: { querystring, response } }, async (request, reply) => {
    const { value, category = 'suggestions' } = request.query;

    const col = app.mongo.db?.collection(category);

    const result = (await col
      ?.find({
        $or: [
          { label: { $regex: value, $options: 'i' } },
          { value: { $regex: value, $options: 'i' } },
        ],
      })
      .limit(20)
      .toArray()) as Array<{ _id: ObjectId; label: string; value: string }>;

    return reply.send(result);
  });
}) as FastifyPluginAsyncTypebox;

import type {
  FastifyInstance,
  FastifyPluginAsync,
  HookHandlerDoneFunction,
} from "fastify";
import fp from "fastify-plugin";
import { Server, type ServerOptions } from "socket.io";

export type FastifySocketioOptions = Partial<ServerOptions> & {
  preClose?: (done: HookHandlerDoneFunction) => void;
};

const fastifySocketIO: FastifyPluginAsync<FastifySocketioOptions> = fp(
  async (fastify, opts: FastifySocketioOptions) => {
    function defaultPreClose(done: HookHandlerDoneFunction) {
      fastify.io.local.disconnectSockets(true);
      done();
    }
    fastify.decorate("io", new Server(fastify.server, opts));
    fastify.addHook("preClose", (done) => {
      if (opts.preClose) {
        return opts.preClose(done);
      }
      return defaultPreClose(done);
    });
    fastify.addHook("onClose", (fastify: FastifyInstance, done) => {
      fastify.io.close();
      done();
    });
  },
  { fastify: ">=4.0.0", name: "fastify-socket.io" },
);

declare module "fastify" {
  interface FastifyInstance {
    io: Server;
  }
}

export default fastifySocketIO;

